import{_ as r,H as e,f as t,i as l}from"./chunks/framework.DLd0CbzH.js";const b=JSON.parse('{"title":"关于 Ay 开放平台","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1780150416000}'),o={name:"about.md"};function i(n,a,s,u,h,d){return e(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="关于-ay-开放平台" tabindex="-1">关于 Ay 开放平台 <a class="header-anchor" href="#关于-ay-开放平台" aria-label="Permalink to &quot;关于 Ay 开放平台&quot;">​</a></h1><h2 id="平台简介" tabindex="-1">平台简介 <a class="header-anchor" href="#平台简介" aria-label="Permalink to &quot;平台简介&quot;">​</a></h2><p>Ay 开放平台是一个由个人开发者 <strong>韵典（AeYunDian）</strong> 打造的 API 服务集合。旨在为开发者、学习者、小型项目提供<strong>简单、可靠、无需认证</strong>的 API 接口。所有服务均免费开放，开箱即用。</p><p>平台目前提供 IP 归属地查询、QQ 好友一键添加、短链解析、文本暂存（AyPass）等实用功能，未来还将持续增加更多服务。</p><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><ul><li><strong>运行环境</strong>：Cloudflare Workers（全球边缘网络）</li><li><strong>后端语言</strong>：JavaScript (ES2022)</li><li><strong>数据库</strong>：Cloudflare D1 (SQLite)</li><li><strong>缓存/存储</strong>：Cloudflare KV</li><li><strong>前端文档</strong>：VitePress</li><li><strong>域名</strong>：undz.cn / io.hb.cn</li></ul><p>所有 API 均部署在 Cloudflare 的边缘节点上，享受低延迟和高可用性。</p><h2 id="开发者寄语" tabindex="-1">开发者寄语 <a class="header-anchor" href="#开发者寄语" aria-label="Permalink to &quot;开发者寄语&quot;">​</a></h2><blockquote><p>我从三年级下学期开始接触编程，从写第一个“Hello World”到搭建自己的网站，再到开发完整的 API 服务，这条路充满挑战也充满乐趣。Ay 开放平台是我将所学付诸实践的成果，希望能帮助到同样热爱技术的你。如果有任何建议或问题，欢迎通过下方渠道联系我。</p></blockquote><h2 id="开源与许可" tabindex="-1">开源与许可 <a class="header-anchor" href="#开源与许可" aria-label="Permalink to &quot;开源与许可&quot;">​</a></h2><p>本平台后端代码已部分开源在 <a href="https://github.com/AeYunDian/api" target="_blank" rel="noreferrer">GitHub</a>。<br> 平台文档及部分工具采用 <strong>MIT 许可证</strong> 发布，你可以自由使用、修改、分发。</p><h2 id="联系与支持" tabindex="-1">联系与支持 <a class="header-anchor" href="#联系与支持" aria-label="Permalink to &quot;联系与支持&quot;">​</a></h2><ul><li><strong>GitHub Issues</strong>：<a href="https://github.com/AeYunDian/open_platform/issues" target="_blank" rel="noreferrer">提交问题或建议</a></li><li><strong>BiliBili</strong>：<a href="https://space.bilibili.com/3494370328185235" target="_blank" rel="noreferrer">https://space.bilibili.com/3494370328185235</a></li><li><strong>邮箱</strong>：<a href="mailto:admin@exm.undz.cn" target="_blank" rel="noreferrer">admin@exm.undz.cn</a></li></ul><hr><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h2><ul><li>感谢 Cloudflare，让个人开发者也能拥有全球级基础设施。</li><li>感谢所有在 GitHub 上提出建议和反馈的朋友。</li><li>感谢我的家人和老师对我学习编程的支持。</li></ul><p><strong>Ay 开放平台</strong> © 2025-2026 韵典 (AeYunDian)</p>',17)])])}const p=r(o,[["render",i]]);export{b as __pageData,p as default};
